 1→import { useCallback, useMemo } from "react";
 2→import { useScrollToSelected } from "../hooks/useScrollToSelected";
 3→import { useAutoScroll } from "../hooks/useAutoScroll";
 4→import { useRegisterViewActions, type ViewActionsRef } from "../hooks/useViewActions";
 5→import type { DisplayMessage } from "../types";
 6→import { MessageItem } from "./MessageItem";
 7→
 8→interface MessageListProps {
 9→  messages: DisplayMessage[];
10→  selectedIndex: number;
11→  expandedSet: Set<number>;
12→  ongoing: boolean;
13→  onSelect: (index: number) => void;
14→  onToggle: (index: number) => void;
15→  onOpenDetail: (index: number) => void;
16→  viewActionsRef: ViewActionsRef;
17→  onExpandAll: () => void;
18→  onCollapseAll: () => void;
19→}
20→
21→export function MessageList({
22→  messages,
23→  selectedIndex,
24→  expandedSet,
25→  ongoing,
26→  onSelect,
27→  onToggle,
28→  onOpenDetail,
29→  viewActionsRef,
30→  onExpandAll,
31→  onCollapseAll,
32→}: MessageListProps) {
33→  useRegisterViewActions(viewActionsRef, { expandAll: onExpandAll, collapseAll: onCollapseAll });
34→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
35→  const selectedRef = useScrollToSelected(selectedIndex);
36→
37→  const handleClick = useCallback(
38→    (index: number) => {
39→      if (selectedIndex === index) {
40→        onToggle(index);
41→      } else {
42→        onSelect(index);
43→      }
44→    },
45→    [selectedIndex, onSelect, onToggle],
46→  );
47→
48→  // Chronological order: oldest messages first
49→  const ordered = useMemo(() => {
50→    const indices: number[] = [];
51→    for (let i = 0; i < messages.length; i++) {
52→      indices.push(i);
53→    }
54→    return indices;
55→  }, [messages.length]);
56→
57→  return (
58→    <div className="message-list" ref={listRef}>
59→      {messages.length === 0 && <div className="message-list__empty">No messages loaded</div>}
60→      {ordered.map((i) => {
61→        const msg = messages[i];
62→        if (msg.role === "compact") {
63→          return <CompactSeparator key={i} content={msg.content} />;
64→        }
65→
66→        const isSelected = i === selectedIndex;
67→        const isLast = i === messages.length - 1;
68→
69→        return (
70→          <MessageItem
71→            key={i}
72→            ref={isSelected ? selectedRef : undefined}
73→            message={msg}
74→            index={i}
75→            isSelected={isSelected}
76→            isExpanded={expandedSet.has(i)}
77→            onClick={handleClick}
78→            onOpenDetail={onOpenDetail}
79→            isOngoing={isLast && ongoing}
80→          />
81→        );
82→      })}
83→    </div>
84→  );
85→}
86→
87→function CompactSeparator({ content }: { content: string }) {
88→  return (
89→    <div className="compact-separator">
90→      <div className="compact-separator__line">
91→        <span className="compact-separator__rule" />
92→        <span>{content}</span>
93→        <span className="compact-separator__rule" />
94→      </div>
95→    </div>
96→  );
97→}
