194→/**
195→ * Pretty-prints a JSON string. Returns the original string on parse failure.
196→ */
197→export function formatJson(input: string): string {
198→  try {
199→    return JSON.stringify(JSON.parse(input), null, 2);
200→  } catch {
201→    return input;
202→  }
203→}
