14→/** Turns "claude-opus-4-6" into "opus4.6". */
15→export function shortModel(m: string): string {
16→  const s = m.replace(/^claude-/, "");
17→  const dashIdx = s.indexOf("-");
18→  if (dashIdx === -1) return s;
19→  const family = s.slice(0, dashIdx);
20→  const rest = s.slice(dashIdx + 1);
21→  const vParts = rest.split("-");
22→  let version = vParts[0];
23→  if (vParts.length >= 2) {
24→    version = vParts[0] + "." + vParts[1];
25→  }
26→  return family + version;
27→}
28→
29→/** Returns hex color for a model string (matches web theme). */
30→export function modelColor(m: string): string {
31→  return _getModelColor(m);
32→}
33→
34→/** Returns hex color for a message role (matches web theme). */
35→export function roleColor(role: string): string {
36→  switch (role) {
37→    case "claude":
38→      return colors.textSecondary;
39→    case "user":
40→      return colors.accent;
41→    case "system":
42→      return colors.textMuted;
43→    default:
44→      return colors.textPrimary;
45→  }
46→}
47→
48→/** Returns a Nerd Font icon for a message role (matches Go TUI). */
49→export function roleIcon(role: string): string {
50→  switch (role) {
51→    case "claude":
52→      return IconClaude;
53→    case "user":
54→      return IconUser;
55→    case "system":
56→      return IconSystem;
57→    default:
58→      return " ";
59→  }
60→}
61→
62→/** Returns the first non-empty line of text. */
63→export function firstLine(text: string): string {
64→  const idx = text.indexOf("\n");
65→  return idx === -1 ? text : text.slice(0, idx);
66→}
67→
68→/** Pretty-prints a JSON string. Returns original on parse failure. */
69→export function formatJson(input: string): string {
70→  try {
71→    return JSON.stringify(JSON.parse(input), null, 2);
72→  } catch {
73→    return input;
74→  }
75→}
