  1→import { useState, useEffect, useCallback, useRef, type ReactNode } from "react";
  2→import { IoMdCloseCircle } from "react-icons/io";
  3→
  4→interface PopoutModalProps {
  5→  onClose: () => void;
  6→  header: ReactNode;
  7→  children: ReactNode;
  8→  initialWidth?: number;
  9→  initialHeight?: number;
 10→}
 11→
 12→export function PopoutModal({
 13→  onClose,
 14→  header,
 15→  children,
 16→  initialWidth,
 17→  initialHeight,
 18→}: PopoutModalProps) {
 19→  const [size, setSize] = useState(() => ({
 20→    width: initialWidth ?? Math.round(window.innerWidth * 0.8),
 21→    height: initialHeight ?? Math.round(window.innerHeight * 0.8),
 22→  }));
 23→  const resizing = useRef<{
 24→    startX: number;
 25→    startY: number;
 26→    startW: number;
 27→    startH: number;
 28→  } | null>(null);
 29→  const justResized = useRef(false);
 30→
 31→  useEffect(() => {
 32→    const handler = (e: KeyboardEvent) => {
 33→      if (e.key === "Escape") onClose();
 34→    };
 35→    window.addEventListener("keydown", handler);
 36→    return () => window.removeEventListener("keydown", handler);
 37→  }, [onClose]);
 38→
 39→  const onResizeStart = useCallback(
 40→    (e: React.MouseEvent) => {
 41→      e.preventDefault();
 42→      resizing.current = {
 43→        startX: e.clientX,
 44→        startY: e.clientY,
 45→        startW: size.width,
 46→        startH: size.height,
 47→      };
 48→      justResized.current = true;
 49→
 50→      const onMouseMove = (ev: MouseEvent) => {
 51→        if (!resizing.current) return;
 52→        const newW = Math.max(
 53→          400,
 54→          resizing.current.startW + (ev.clientX - resizing.current.startX),
 55→        );
 56→        const newH = Math.max(
 57→          300,
 58→          resizing.current.startH + (ev.clientY - resizing.current.startY),
 59→        );
 60→        setSize({ width: newW, height: newH });
 61→      };
 62→
 63→      const onMouseUp = () => {
 64→        resizing.current = null;
 65→        document.removeEventListener("mousemove", onMouseMove);
 66→        document.removeEventListener("mouseup", onMouseUp);
 67→        setTimeout(() => {
 68→          justResized.current = false;
 69→        }, 100);
 70→      };
