.message-detail {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.message-detail__header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-width: 0;
}

.message-detail__back {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--accent);
  cursor: pointer;
  font-size: 12px;
  background: none;
  border: none;
  font-family: inherit;
}

.message-detail__back:hover {
  text-decoration: underline;
}

.message-detail__title {
  font-weight: 600;
  font-size: 13px;
}

.message-detail__meta {
  font-size: 11px;
  color: var(--text-secondary);
  margin-left: auto;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
  flex-shrink: 1;
}

.message-detail__body {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  min-width: 0;
}

.message-detail__content {
  max-width: 900px;
  margin: 0 auto;
  min-width: 0;
}

.agent-panel .message-detail__content {
  max-width: none;
}

.message-detail__ongoing {
  display: flex;
  justify-content: center;
  padding: 16px 0;
}

.message-detail__text {
  font-size: 13px;
  line-height: 1.6;
  white-space: pre-wrap;
  word-break: break-word;
  margin-bottom: 16px;
}

/* Markdown rendering */
.message-detail__text h1,
.message-detail__text h2,
.message-detail__text h3 {
  color: var(--text-primary);
  margin: 16px 0 8px;
}

.message-detail__text code {
  background: var(--bg-elevated);
  padding: 1px 4px;
  border-radius: 3px;
  font-size: 12px;
}

.message-detail__text pre {
  background: var(--bg-elevated);
