/* ============================================================
   claude-code-trace — Dark theme matching the Go TUI
   ============================================================ */

:root {
  /* Background */
  --bg: #1a1a2e;
  --bg-surface: #16213e;
  --bg-elevated: #222244;
  --bg-hover: #2a2a4a;

  /* Text hierarchy */
  --text-primary: #d0d0d0;
  --text-secondary: #8a8a8a;
  --text-dim: #767676;
  --text-muted: #585858;

  /* Accents */
  --accent: #5fafff;
  --error: #ff0000;
  --info: #5f87ff;

  /* Surfaces */
  --border: #5f5f87;

  /* Model family */
  --model-opus: #ff5f87;
  --model-sonnet: #5fafff;
  --model-haiku: #87d787;

  /* Context usage */
  --context-ok: #87d787;
  --context-warn: #ff8700;
