  /* Permission pills */
  --pill-bypass: #ff0000;
  --pill-accept-edits: #af5fff;
  --pill-plan: #87d787;

  /* Picker */
  --picker-selected-bg: #3a3a3a;

  /* Ongoing */
  --ongoing: #5faf00;

  /* Git */
  --git-branch: #af5fff;

  /* Token high */
  --token-high: #ff8700;

  /* Icons */
  --icon-claude: #d4a017;
  --icon-user: #5fafff;
  --icon-system: #8a8aaa;
  --icon-warning: #ff8700;
  --icon-thinking: #e0c050;
