/* ============================================================
   claude-code-trace — Dark theme matching the Go TUI
   ============================================================ */

:root {
  /* Background */
  --bg: #1a1a2e;
  --bg-surface: #16213e;
  --bg-elevated: #222244;
  --bg-hover: #2a2a4a;

  /* Text hierarchy */
  --text-primary: #d0d0d0;
  --text-secondary: #8a8a8a;
  --text-dim: #767676;
  --text-muted: #585858;

  /* Accents */
  --accent: #5fafff;
  --error: #ff0000;
  --info: #5f87ff;

  /* Surfaces */
  --border: #5f5f87;

  /* Model family */
  --model-opus: #ff5f87;
  --model-sonnet: #5fafff;
  --model-haiku: #87d787;

  /* Context usage */
  --context-ok: #87d787;
  --context-warn: #ff8700;
  --context-crit: #ff0000;

  /* Permission pills */
  --pill-bypass: #ff0000;
  --pill-accept-edits: #af5fff;
  --pill-plan: #87d787;

  /* Picker */
  --picker-selected-bg: #3a3a3a;

  /* Ongoing */
  --ongoing: #5faf00;

  /* Git */
  --git-branch: #af5fff;

  /* Token high */
  --token-high: #ff8700;

  /* Icons */
  --icon-claude: #d4a017;
  --icon-user: #5fafff;
  --icon-system: #8a8aaa;
  --icon-warning: #ff8700;
  --icon-thinking: #e0c050;
  --icon-output: #63b3ed;
  --icon-tool: #9a8aef;
  --icon-hook: #87d787;
  --icon-tokens: #d4a017;
  --icon-duration: #8a8aaa;
  --icon-agents: #63b3ed;
  --icon-spawn: #af5fff;
  --icon-search: #5fafff;
  --icon-edit: #e0c050;
  --icon-read: #87d787;
  --icon-bash: #9a8aef;
  --icon-web: #5fafff;
  --icon-mcp: #af5fff;
  --icon-cron: #8a8aaa;
  --icon-git: #af5fff;

  /* Agent panel */
  --agent-panel: #63b3ed;

  /* Misc */
  --scrollbar-thumb: #444466;
  --scrollbar-track: transparent;
}

