  /* Context usage */
  --context-ok: #87d787;
  --context-warn: #ff8700;
  --context-crit: #ff0000;

  /* Permission pills */
  --pill-bypass: #ff0000;
  --pill-accept-edits: #af5fff;
  --pill-plan: #87d787;

  /* Picker */
  --picker-selected-bg: #3a3a3a;

  /* Ongoing */
  --ongoing: #5faf00;

  /* Git */
  --git-branch: #af5fff;

  /* Token high */
