 87→/// Parse a single JSONL line into an Entry.
 88→/// Returns None if the JSON is invalid or the entry has no UUID.
 89→pub fn parse_entry(line: &[u8]) -> Option<Entry> {
 90→    let e: Entry = serde_json::from_slice(line).ok()?;
 91→    if e.uuid.is_empty() && e.leaf_uuid.is_empty() {
 92→        return None;
 93→    }
 94→    Some(e)
 95→}
