122→/// Build chunks from classified messages.
123→pub fn build_chunks(msgs: &[ClassifiedMsg]) -> Vec<Chunk> {
124→    let mut chunks = Vec::new();
125→    let mut ai_buf: Vec<AIMsg> = Vec::new();
126→
127→    let flush = |buf: &mut Vec<AIMsg>, chunks: &mut Vec<Chunk>| {
128→        if buf.is_empty() {
129→            return;
130→        }
131→        chunks.push(merge_ai_buffer(buf));
132→        buf.clear();
133→    };
134→
135→    for msg in msgs {
136→        match msg {
137→            ClassifiedMsg::User(m) => {
138→                flush(&mut ai_buf, &mut chunks);
139→                chunks.push(Chunk {
140→                    chunk_type: ChunkType::User,
141→                    timestamp: m.timestamp,
142→                    user_text: m.text.clone(),
143→                    ..Default::default()
144→                });
145→            }
146→            ClassifiedMsg::System(m) => {
147→                flush(&mut ai_buf, &mut chunks);
148→                chunks.push(Chunk {
149→                    chunk_type: ChunkType::System,
150→                    timestamp: m.timestamp,
151→                    output: m.output.clone(),
152→                    is_error: m.is_error,
153→                    ..Default::default()
154→                });
155→            }
156→            ClassifiedMsg::AI(m) => {
157→                ai_buf.push(m.clone());
158→            }
159→            ClassifiedMsg::Teammate(m) => {
160→                // Fold into AI buffer as synthetic AIMsg with teammate block.
161→                ai_buf.push(AIMsg {
162→                    timestamp: m.timestamp,
163→                    is_meta: true,
164→                    blocks: vec![ContentBlock {
165→                        block_type: "teammate".to_string(),
166→                        text: m.text.clone(),
167→                        teammate_id: m.teammate_id.clone(),
168→                        teammate_color: m.color.clone(),
169→                        ..Default::default()
170→                    }],
171→                    ..AIMsg {
172→                        timestamp: m.timestamp,
173→                        model: String::new(),
174→                        text: String::new(),
175→                        thinking_count: 0,
176→                        tool_calls: Vec::new(),
177→                        blocks: Vec::new(),
178→                        usage: Usage::default(),
179→                        stop_reason: String::new(),
180→                        is_meta: true,
181→                    }
182→                });
183→            }
184→            ClassifiedMsg::Hook(m) => {
185→                // Fold hook events into the AI buffer as synthetic AIMsg with a hook block.
186→                ai_buf.push(AIMsg {
187→                    timestamp: m.timestamp,
188→                    model: String::new(),
189→                    text: String::new(),
190→                    thinking_count: 0,
191→                    tool_calls: Vec::new(),
192→                    blocks: vec![ContentBlock {
193→                        block_type: "hook_event".to_string(),
194→                        text: m.command.clone(),
195→                        tool_name: m.hook_name.clone(),
196→                        tool_id: m.hook_event.clone(),
197→                        ..Default::default()
198→                    }],
199→                    usage: Usage::default(),
200→                    stop_reason: String::new(),
201→                    is_meta: true,
202→                });
203→            }
204→            ClassifiedMsg::Compact(m) => {
205→                flush(&mut ai_buf, &mut chunks);
206→                chunks.push(Chunk {
207→                    chunk_type: ChunkType::Compact,
208→                    timestamp: m.timestamp,
209→                    output: m.text.clone(),
210→                    ..Default::default()
211→                });
212→            }
213→        }
214→    }
215→    flush(&mut ai_buf, &mut chunks);
216→    chunks
217→}
