 27→/// Pricing per million tokens for a model family.
 28→struct ModelPricing {
 29→    input: f64,
 30→    output: f64,
 31→    cache_read: f64,
 32→    cache_write: f64,
 33→}
 34→
 35→fn pricing_for_model(model: &str) -> ModelPricing {
 36→    let m = model.to_lowercase();
 37→    if m.contains("opus") {
 38→        ModelPricing {
 39→            input: 5.0,
 40→            output: 25.0,
 41→            cache_read: 0.5,
 42→            cache_write: 6.25,
 43→        }
 44→    } else if m.contains("haiku") {
 45→        ModelPricing {
 46→            input: 1.0,
 47→            output: 5.0,
 48→            cache_read: 0.1,
 49→            cache_write: 1.25,
 50→        }
 51→    } else {
 52→        // Default to sonnet
 53→        ModelPricing {
 54→            input: 3.0,
 55→            output: 15.0,
 56→            cache_read: 0.3,
 57→            cache_write: 3.75,
 58→        }
 59→    }
 60→}
