 62→/// Insert a token snapshot, preferring entries with stop_reason (complete responses)
 63→/// over partial streaming snapshots with understated output_tokens.
 64→pub fn insert_best_snapshot(
 65→    map: &mut HashMap<String, TokenSnapshot>,
 66→    key: String,
 67→    snap: TokenSnapshot,
 68→) {
 69→    match map.get(&key) {
 70→        Some(existing) => {
 71→            // Prefer complete entries (has_stop_reason) over partial ones.
 72→            // Among same completeness, prefer higher output (later streaming = more tokens).
 73→            if (!existing.has_stop_reason && snap.has_stop_reason)
 74→                || (existing.has_stop_reason == snap.has_stop_reason
 75→                    && snap.output >= existing.output)
 76→            {
 77→                map.insert(key, snap);
 78→            }
 79→        }
 80→        None => {
 81→            map.insert(key, snap);
 82→        }
 83→    }
 84→}
