  3→/// ToolCategory classifies tool calls into broad functional groups.
  4→/// Used by the GUI to assign per-category icons and colors.
  5→#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
  6→pub enum ToolCategory {
  7→    Read,
  8→    Edit,
  9→    Write,
 10→    Bash,
 11→    Grep,
 12→    Glob,
 13→    Task,
 14→    Tool,
 15→    Web,
 16→    Cron,
 17→    Mcp,
 18→    Other,
 19→}
 20→
 21→/// CategorizeToolName maps a raw tool name to a ToolCategory.
 22→pub fn categorize_tool_name(name: &str) -> ToolCategory {
 23→    match name {
 24→        // Claude Code core tools
 25→        "Read" => ToolCategory::Read,
 26→        "Edit" => ToolCategory::Edit,
 27→        "Write" | "NotebookEdit" => ToolCategory::Write,
 28→        "Bash" => ToolCategory::Bash,
 29→        "Grep" => ToolCategory::Grep,
 30→        "Glob" => ToolCategory::Glob,
 31→        "Task" | "Agent" | "TaskCreate" | "TaskUpdate" | "TaskList" | "TaskGet" | "TaskStop"
 32→        | "TaskOutput" => ToolCategory::Task,
 33→        "TeamCreate" | "TeamDelete" | "SendMessage" => ToolCategory::Task,
 34→        "Skill"
 35→        | "ToolSearch"
 36→        | "LSP"
 37→        | "TodoWrite"
 38→        | "AskUserQuestion"
 39→        | "ListMcpResourcesTool"
 40→        | "ReadMcpResourceTool" => ToolCategory::Tool,
 41→        "EnterPlanMode" | "ExitPlanMode" | "EnterWorktree" | "ExitWorktree" => ToolCategory::Tool,
 42→        "WebFetch" | "WebSearch" => ToolCategory::Web,
 43→        "CronCreate" | "CronDelete" | "CronList" => ToolCategory::Cron,
 44→
 45→        _ if name.starts_with("mcp__") => ToolCategory::Mcp,
 46→        _ => ToolCategory::Other,
 47→    }
 48→}
 49→
 50→/// Parses an MCP tool name like "mcp__server-name__tool_name" into (server, tool).
 51→/// Returns None if the name doesn't match the mcp__ prefix pattern.
 52→pub fn parse_mcp_tool_name(name: &str) -> Option<(&str, &str)> {
 53→    let rest = name.strip_prefix("mcp__")?;
 54→    let sep = rest.find("__")?;
 55→    let server = &rest[..sep];
 56→    let tool = &rest[sep + 2..];
 57→    if server.is_empty() || tool.is_empty() {
 58→        return None;
 59→    }
 60→    Some((server, tool))
 61→}
 62→
 63→/// Returns a human-friendly display name for an MCP tool.
 64→/// e.g. "mcp__chrome-devtools__take_screenshot" -> "MCP chrome-devtools"
 65→pub fn mcp_display_name(name: &str) -> String {
 66→    match parse_mcp_tool_name(name) {
 67→        Some((server, _)) => format!("MCP {server}"),
 68→        None => name.to_string(),
 69→    }
 70→}
