117→/// Shorten model name: "claude-opus-4-6" -> "opus4.6"
118→fn short_model(m: &str) -> String {
119→    let m = m.strip_prefix("claude-").unwrap_or(m);
120→    let parts: Vec<&str> = m.splitn(2, '-').collect();
121→    if parts.len() == 2 {
122→        let family = parts[0];
123→        let v_parts: Vec<&str> = parts[1].splitn(3, '-').collect();
124→        let version = if v_parts.len() >= 2 {
125→            format!("{}-{}", v_parts[0], v_parts[1])
126→        } else {
127→            v_parts[0].to_string()
128→        };
129→        format!("{}{}", family, version.replace('-', "."))
130→    } else {
131→        m.to_string()
132→    }
133→}
