              hook:
            </Text>
            <Text>
              {item.hook_event}: {item.hook_name}
            </Text>
          </Box>
          {item.hook_command && (
            <Box gap={1}>
              <Text color={colors.textMuted} bold>
                cmd:
              </Text>
              <Text dimColor>{item.hook_command}</Text>
            </Box>
          )}
        </Box>
      );
    default:
      return (
        <Box flexDirection="column" paddingLeft={4}>
          <Text wrap="truncate">{clamp(item.text)}</Text>
        </Box>
      );
  }
}
